questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(4)+1;

/* ===== Given values per set ===== */
/*  Set | Z0 | Rg  | RL  | Vg  | l_m  */
/*  1   | 50 | 150 | 150 | 60  | 1.0  */
/*  2   | 50 | 100 | 25  | 30  | 1.5  */
/*  3   | 75 | 150 | 25  | 60  | 1.0  */
/*  4   | 50 | 150 | 25  | 100 | 0.5  */

Z0:  if set=1 then 50  else if set=2 then 50  else if set=3 then 75  else 50;
Rg:  if set=1 then 150 else if set=2 then 100 else if set=3 then 150 else 150;
RL:  if set=1 then 150 else if set=2 then 25  else if set=3 then 25  else 25;
Vg:  if set=1 then 60  else if set=2 then 30  else if set=3 then 60  else 100;
l_m: if set=1 then 1.0 else if set=2 then 1.5 else if set=3 then 1.0 else 0.5;

/* ===== Constants ===== */
vp: 2e8;   /* 2c/3 */

/* ===== Teacher answers ===== */

/* (a) Gamma_L — load reflection coefficient */
ta1: float((RL - Z0)/(RL + Z0));

/* (b) Gamma_g — generator reflection coefficient */
ta2: float((Rg - Z0)/(Rg + Z0));

/* (c) V1plus — initial forward-travelling voltage wave */
ta3: float(Vg * Z0 / (Rg + Z0));

/* (d) T_val — one-way travel time */
ta4: float(l_m / vp);

/* (e) Vss — steady-state voltage at load */
ta5: float(Vg * RL / (Rg + RL));

/* ===== Display variables ===== */
T_ns: float(ta4 * 1e9);
vp_disp: 2;   /* for showing "2 × 10^8 m/s" */

/* ===== Bounce diagram voltage steps at load (z = l) ===== */
/* Voltage changes at odd multiples of T: T, 3T, 5T, 7T */
V_step1: float(ta3 * (1 + ta1));
V_step2: float(V_step1 + ta3 * ta1 * ta2 * (1 + ta1));
V_step3: float(V_step2 + ta3 * (ta1 * ta2)^2 * (1 + ta1));
V_step4: float(V_step3 + ta3 * (ta1 * ta2)^3 * (1 + ta1));

/* ===== Correct points for JSXGraph grading (t-axis in units of T) ===== */
correct_points: [[1, V_step1], [3, V_step2], [5, V_step3], [7, V_step4]];

/* ===== Y-axis bounds for JSXGraph ===== */
/* ceiling/floor guarantee clean integer output for JS interpolation */
y_max: ceiling(float(max(Vg, V_step1, V_step2, V_step3, V_step4)) * 1.2);
y_min: floor(float(min(0, V_step1, V_step2, V_step3, V_step4)) * 1.2 - 2);

/* ===== Grading tolerances ===== */
y_tol: float(max(1.0, 0.05 * Vg));

feedbackvariables.text:
/* Point Placement Grading — Adapted from graph-presets.js */
/* correct_points is defined in questionvariables as:
   [[1, V_step1], [3, V_step2], [5, V_step3], [7, V_step4]] */

/* Convert student answer from matrix to list of lists for safe indexing.
   Maxima parses [[1,2],[3,4]] as matrix([1,2],[3,4]), not a nested list.
   args() extracts the matrix rows as a plain list. */
student_raw: ans6;
student_pts: if matrixp(student_raw) then args(student_raw) else student_raw;

/* Check that student placed the correct number of points */
student_count: length(student_pts);
correct_count: is(student_count = 4);

/* Tolerances for point matching */
x_tol: 0.8;
/* y_tol is defined in questionvariables: max(1.0, 0.05*Vg) */

/* Use nearest-point matching: for each expected point, find the closest student point.
   This avoids order-dependency — students don't need to place points in a specific order. */
matched_expected: makelist(false, i, 1, 4);
matched_student: makelist(false, i, 1, student_count);
/* Track actual match pairing: which student index was matched to each expected point */
match_pair: makelist(0, i, 1, 4);

/* For each expected point, find the closest unmatched student point */
match_results: block([],
    for ei: 1 thru 4 do (
        block([best_dist, best_si, ex, ey, sx, sy, dx, dy],
            ex: correct_points[ei][1],
            ey: correct_points[ei][2],
            best_dist: 99999,
            best_si: 0,
            for si: 1 thru student_count do (
                if not matched_student[si] then (
                    sx: student_pts[si][1],
                    sy: student_pts[si][2],
                    dx: abs(sx - ex),
                    dy: abs(sy - ey),
                    if is(dx < x_tol) and is(dy < y_tol) then (
                        block([d],
                            d: sqrt(dx^2 + dy^2),
                            if is(d < best_dist) then (best_dist: d, best_si: si)
                        )
                    )
                )
            ),
            if is(best_si > 0) then (
                matched_expected[ei]: true,
                matched_student[best_si]: true,
                match_pair[ei]: best_si
            )
        )
    ),
    matched_expected
);

/* Count how many expected points were matched */
pt_checks: makelist(if matched_expected[i] then 1 else 0, i, 1, 4);
num_correct: apply("+", pt_checks);
all_correct: is(num_correct >= 3);

/* Build detailed feedback table showing which points matched.
   Uses match_pair to look up the actual paired student point for each expected point. */
feedback_parts: makelist(
    sconcat(
        "<tr><td>", i, "</td>",
        "<td>(", string(correct_points[i][1]), ", ", string(correct_points[i][2]), ")</td>",
        "<td>",
        if is(match_pair[i] > 0) then
            sconcat("(", string(student_pts[match_pair[i]][1]), ", ", string(student_pts[match_pair[i]][2]), ")")
        else "no match",
        "</td>",
        "<td>", if is(pt_checks[i] = 1) then "&#10004;" else "&#10008;", "</td></tr>"
    ),
    i, 1, 4
);

feedback_msg: sconcat(
    "<strong>", string(num_correct), " / 4 points correct</strong>",
    "<table border='1' cellpadding='4' style='border-collapse:collapse;margin-top:8px'>",
    "<tr><th>#</th><th>Expected (t/T, V)</th><th>Your closest</th><th>Result</th></tr>",
    simplode(feedback_parts, ""),
    "</table>"
);
